import { NextResponse } from 'next/server'
import { createStaticClient } from '@/lib/supabase/static'
import { toPostCardDTO } from '@/lib/dal/mappers'
import type { PostCard } from '@/types/post.types'

/**
 * GET /api/related-jobs?postId=xxx
 *
 * Dynamically fetches related jobs/posts based on the `related_post_ids` array
 * generated by our SEO Engine's clustering and semantic affinity functions.
 * Adds differentiation to the detail pages by grouping smart related content.
 */
export async function GET(request: Request) {
    const { searchParams } = new URL(request.url)
    const postId = searchParams.get('postId')

    if (!postId) {
        return NextResponse.json({ error: 'postId is required' }, { status: 400 })
    }

    try {
        const supabase = createStaticClient()

        // 1. Fetch the source post to get related IDs
        const { data: sourcePost, error: sourceError } = await supabase
            .from('posts')
            .select('related_post_ids, content_cluster_id, type')
            .eq('id', postId)
            .single()

        if (sourceError || !sourcePost) {
            return NextResponse.json({ error: 'Post not found' }, { status: 404 })
        }

        const postRecord = sourcePost as any
        const relatedIds = postRecord.related_post_ids || []
        
        let posts: PostCard[] = []

        // 2. Fetch the related posts by ID
        if (relatedIds.length > 0) {
            const POST_CARD_COLUMNS = `
              id, type, application_status, title, slug, excerpt,
              state_slug, state_name,
              org_name, org_short_name, org_logo_url,
              category_slug, category_name,
              qualification,
              featured_image, featured_image_alt,
              view_count, reading_time_min,
              application_start_date, application_end_date,
              published_at, updated_at
            `.trim()

            const { data: relatedData } = await supabase
                .from('v_published_posts')
                .select(POST_CARD_COLUMNS)
                .in('id', relatedIds)
                .limit(4)

            if (relatedData) {
                posts = relatedData.map(toPostCardDTO)
            }
        }

        // 3. Fallback: If no strict affinity, fallback to same cluster
        if (posts.length < 4 && postRecord.content_cluster_id) {
            const { data: fallbackData } = await supabase
                .from('v_published_posts')
                .select(`
                  id, type, application_status, title, slug, excerpt,
                  state_slug, state_name,
                  org_name, org_short_name, org_logo_url,
                  category_slug, category_name,
                  qualification,
                  featured_image, featured_image_alt,
                  view_count, reading_time_min,
                  application_start_date, application_end_date,
                  published_at, updated_at
                `.trim())
                .eq('type', postRecord.type)
                .neq('id', postId)
                .limit(4 - posts.length)

            if (fallbackData) {
                 const fallbackPosts = fallbackData.map(toPostCardDTO)
                 // merge avoiding duplicates
                 const existingIds = new Set(posts.map(p => p.id))
                 fallbackPosts.forEach(fp => {
                     if (!existingIds.has(fp.id)) posts.push(fp)
                 })
            }
        }

        return NextResponse.json({ data: posts }, {
            headers: {
                'Cache-Control': 'public, s-maxage=3600, stale-while-revalidate=86400',
            }
        })
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 })
    }
}
